const ROMAN = ["","I","II","III","IV","V","VI","VII","VIII","IX","X","XI","XII"];
const MONTHS = ["","January","February","March","April","May","June","July","August","September","October","November","December"];
const SERVICES = ["AI Integration","Custom Development","Digital Marketing","Procurement"];
const SVC_CODE = {"AI Integration":"AI","Custom Development":"DEV","Digital Marketing":"DM","Procurement":"PROC"};
const STATUSES = ["Initiated","In Progress","Review","Completed","On Hold","Cancelled"];
const PAY_TERMS = ["Immediate","NET 7","NET 14","NET 30","NET 60","50% DP — 50% Completion","30% — 40% — 30%"];
const PAY_METHODS = ["Bank Transfer","Cash","E-Wallet","Check"];
const VOUCHER_TYPES = [{k:"receipt",l:"Receipt Voucher",code:"RV"},{k:"payment",l:"Payment Voucher",code:"PV"},{k:"advance",l:"Advance Voucher",code:"AV"},{k:"refund",l:"Refund Voucher",code:"RFV"}];
const VOUCHER_MAP = Object.fromEntries(VOUCHER_TYPES.map(v=>[v.k,v]));
const APPROVAL_STATUSES = ["Pending Approval","Approved","Rejected","Done"];
const ACCT_DR = ["Cash","Accounts Receivable","Inventory","Purchase Advance","Input VAT","Prepaid Income Tax","Administrative Expense","Operational Expense","Project Expense","Service Expense","Cost of Goods Sold","Notary","Intangible Assets"];
const ACCT_CR = ["Cash","Service Revenue","Sales","Other Income","Accounts Payable","Output VAT","Equity","Trade Payable","Loan"];
const PIE_COLORS = ["#00d47b","#6366f1","#f59e0b","#ff4747","#06b6d4","#ec4899"];

const fmt = n => "Rp" + Number(n||0).toLocaleString("id-ID");
const fDate = d => d ? new Date(d).toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"}) : "-";
const sDate = d => d ? new Date(d).toLocaleDateString("en-GB",{day:"2-digit",month:"2-digit",year:"numeric"}) : "-";
const rom = d => ROMAN[new Date(d||Date.now()).getMonth()+1];
const yr = d => new Date(d||Date.now()).getFullYear();
const uid = () => Date.now().toString(36)+Math.random().toString(36).slice(2,7);
const today = () => new Date().toISOString().split("T")[0];
function pw(html){const w=window.open("","_blank","width=820,height=900");if(w){w.document.write(html);w.document.close();}}
function fileToB64(file){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res({name:file.name,size:file.size,data:r.result});r.onerror=()=>rej(new Error("Read failed"));r.readAsDataURL(file);});}
function downloadFile(name,dataUrl){const a=document.createElement("a");a.href=dataUrl;a.download=name;a.click();}

