  const journalGroups=useMemo(()=>{const map={};filteredJournal.forEach(j=>{const base=j.id?.replace(/_cr$/,'')||j.id;if(!map[base])map[base]={dr:null,cr:null};if(j.id?.endsWith('_cr'))map[base].cr=j;else map[base].dr=j;});return Object.entries(map).map(([id,g])=>({id,dr:g.dr,cr:g.cr,date:g.dr?.date||g.cr?.date,description:g.dr?.description||g.cr?.description,refNo:g.dr?.refNo||g.cr?.refNo})).sort((a,b)=>new Date(b.date||0)-new Date(a.date||0));},[filteredJournal]);
  const journalTotals=useMemo(()=>({debit:filteredJournal.reduce((s,j)=>s+Number(j.debit||0),0),credit:filteredJournal.reduce((s,j)=>s+Number(j.credit||0),0)}),[filteredJournal]);
